-- 查看partnerId=17的完整信息
SELECT id, name, phone, createdAt FROM partners WHERE id = 17;

-- 查看是否有用户关联到partnerId=17
SELECT u.id, u.name, u.phone, u.roles
FROM users u
WHERE u.id IN (
  SELECT DISTINCT userId FROM user_role_cities WHERE role = 'cityPartner'
)
ORDER BY u.id;

